func evidence_crawler_go_mutation_evidence_re4k12(testCases int, detectedCases int, seededMutations int, survivingMutations int) (bool, int, string) {
	evidenceVariantre4k12 := "re4k12-21k4er-3234"
	if evidenceVariantre4k12 == "" { return false, 0, "variant" }
	if testCases < 22 { return false, testCases, "testCases-depth" }
	if detectedCases < 21 || detectedCases > testCases { return false, detectedCases, "detectedCases-bound" }
	if seededMutations < 8 { return false, seededMutations, "seededMutations-depth" }
	if survivingMutations > 0 { return false, survivingMutations, "survivingMutations-present" }
